sql:
SELECT followers AS total_followers
FROM playlists
WHERE playlist_id = 0;

external_knowledge:
- 'Highly rated' refers to an average rating greater than 0.7; 
- 'Frequently featured in playlists' means appearing in more than 10 playlists; 
- 'Well-received by users' corresponds to an average user sentiment greater than 0.5; 
- 'Strongly recommended' means an average recommendation score greater than 0.6.

sql:
SELECT fs.song_id, AVG(rs.rating) AS avg_rating
FROM (
  SELECT DISTINCT lh.song_id
  FROM listening_history lh
  JOIN (
    SELECT user_id FROM listening_history GROUP BY user_id HAVING COUNT(song_id) > 5
  ) AS uh ON lh.user_id = uh.user_id
  JOIN (
    SELECT id FROM songs WHERE acousticness > 0.5
  ) AS sa ON lh.song_id = sa.id
) AS fs
JOIN ratings rs ON fs.song_id = rs.song_id
GROUP BY fs.song_id;
